import math

PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """Compare two real numbers with six significant digit precision."""
    if a == 0.0 and b == 0.0:
        return "EQ"
    if a == 0.0:
        return "LT" if b > 0 else "GT"
    if b == 0.0:
        return "GT" if a > 0 else "LT"

    abs_a = abs(a)
    abs_b = abs(b)
    max_val = max(abs_a, abs_b)

    tol = max_val * 1e-6

    if abs(a - b) <= tol:
        return "EQ"
    elif a < b:
        return "LT"
    else:
        return "GT"


def _circle_radius_for_three_points(
    x1: float, y1: float, x2: float, y2: float, x3: float, y3: float
) -> float:
    """Calculate the circumradius of three points. Returns float('inf') if collinear."""
    d = 2 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2))
    if d == 0:
        return float("inf")

    ux = (
        (x1**2 + y1**2) * (y2 - y3)
        + (x2**2 + y2**2) * (y3 - y1)
        + (x3**2 + y3**2) * (y1 - y2)
    ) / d
    uy = (
        (x1**2 + y1**2) * (x3 - x2)
        + (x2**2 + y2**2) * (x1 - x3)
        + (x3**2 + y3**2) * (x2 - x1)
    ) / d

    return math.sqrt((x1 - ux) ** 2 + (y1 - uy) ** 2)


def _triangle_area(
    x1: float, y1: float, x2: float, y2: float, x3: float, y3: float
) -> float:
    """Calculate the area of a triangle given three vertices."""
    return 0.5 * abs(x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2))


def _get_quadrant(x: float, y: float) -> int:
    """
    Return the quadrant (1-4) for a point.
    Priority: I, II, III, IV for ambiguous points on axes.
    """
    if x >= 0 and y >= 0:
        return 1
    elif x < 0 and y >= 0:
        return 2
    elif x < 0 and y < 0:
        return 3
    else:
        return 4


def _angle_at_vertex(
    x1: float, y1: float, x2: float, y2: float, x3: float, y3: float
) -> float:
    """
    Calculate the angle at vertex (x2, y2) formed by points (x1,y1)-(x2,y2)-(x3,y3).
    Returns the angle in radians (0 to PI).
    """
    dx1 = x1 - x2
    dy1 = y1 - y2
    dx2 = x3 - x2
    dy2 = y3 - y2

    dot = dx1 * dx2 + dy1 * dy2
    mag1 = math.sqrt(dx1**2 + dy1**2)
    mag2 = math.sqrt(dx2**2 + dy2**2)

    if mag1 == 0 or mag2 == 0:
        return -1.0

    cos_angle = dot / (mag1 * mag2)
    cos_angle = max(-1.0, min(1.0, cos_angle))
    return math.acos(cos_angle)


def _distance_point_to_line(
    px: float, py: float, x1: float, y1: float, x2: float, y2: float
) -> float:
    """Calculate the perpendicular distance from point (px,py) to line through (x1,y1)-(x2,y2)."""
    num = abs((y2 - y1) * px - (x2 - x1) * py + x2 * y1 - y2 * x1)
    denom = math.sqrt((y2 - y1) ** 2 + (x2 - x1) ** 2)
    if denom == 0:
        return math.sqrt((px - x1) ** 2 + (py - y1) ** 2)
    return num / denom


def _lic1(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of two consecutive data points that are a distance greater than LENGTH1 apart."""
    length1 = params["LENGTH1"]
    for i in range(numpoints - 1):
        dx = x[i + 1] - x[i]
        dy = y[i + 1] - y[i]
        dist_sq = dx * dx + dy * dy
        if realcompare(dist_sq, length1 * length1) == "GT":
            return True
    return False


def _lic2(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of three consecutive data points that cannot all be contained within or on a circle of radius RADIUS1."""
    radius1 = params["RADIUS1"]
    for i in range(numpoints - 2):
        r = _circle_radius_for_three_points(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(r, radius1) == "GT":
            return True
    return False


def _lic3(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of three consecutive data points which form an angle such that angle < (PI - EPSILON) or angle > (PI + EPSILON)."""
    epsilon = params["EPSILON"]
    for i in range(numpoints - 2):
        angle = _angle_at_vertex(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if angle < 0:
            continue
        if realcompare(angle, PI - epsilon) == "LT" or realcompare(
            angle, PI + epsilon
        ) == "GT":
            return True
    return False


def _lic4(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of three consecutive data points that are the vertices of a triangle with area greater than AREA1."""
    area1 = params["AREA1"]
    for i in range(numpoints - 2):
        area = _triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(area, area1) == "GT":
            return True
    return False


def _lic5(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of Q_PTS consecutive data points that lie in more than QUADS quadrants."""
    q_pts = params["Q_PTS"]
    quads = params["QUADS"]
    for i in range(numpoints - q_pts + 1):
        quadrant_set = set()
        for j in range(i, i + q_pts):
            quadrant_set.add(_get_quadrant(x[j], y[j]))
        if len(quadrant_set) > quads:
            return True
    return False


def _lic6(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of two consecutive data points, (X[i], Y[i]) and (X[j], Y[j]), such that X[j] - X[i] < 0 (where i = j - 1)."""
    for i in range(numpoints - 1):
        if realcompare(x[i + 1] - x[i], 0.0) == "LT":
            return True
    return False


def _lic7(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of N_PTS consecutive data points such that at least one of the points lies a distance greater than DIST from the line joining the first and last of these N_PTS points."""
    n_pts = params["N_PTS"]
    dist = params["DIST"]
    if numpoints < 3:
        return False
    for i in range(numpoints - n_pts + 1):
        x_first = x[i]
        y_first = y[i]
        x_last = x[i + n_pts - 1]
        y_last = y[i + n_pts - 1]
        for j in range(i, i + n_pts):
            if realcompare(x_first, x_last) == "EQ" and realcompare(
                y_first, y_last
            ) == "EQ":
                dx = x[j] - x_first
                dy = y[j] - y_first
                point_dist = math.sqrt(dx * dx + dy * dy)
            else:
                point_dist = _distance_point_to_line(
                    x[j], y[j], x_first, y_first, x_last, y_last
                )
            if realcompare(point_dist, dist) == "GT":
                return True
    return False


def _lic8(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of two data points separated by exactly K_PTS consecutive intervening points that are a distance greater than LENGTH1 apart."""
    k_pts = params["K_PTS"]
    length1 = params["LENGTH1"]
    if numpoints < 3:
        return False
    for i in range(numpoints - k_pts - 1):
        j = i + k_pts + 1
        dx = x[j] - x[i]
        dy = y[j] - y[i]
        dist_sq = dx * dx + dy * dy
        if realcompare(dist_sq, length1 * length1) == "GT":
            return True
    return False


def _lic9(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of three data points separated by exactly A_PTS and B_PTS consecutive intervening points, respectively, that cannot be contained within or on a circle of radius RADIUS1."""
    a_pts = params["A_PTS"]
    b_pts = params["B_PTS"]
    radius1 = params["RADIUS1"]
    if numpoints < 5:
        return False
    for i in range(numpoints - a_pts - b_pts - 2):
        j = i + a_pts + 1
        k = j + b_pts + 1
        r = _circle_radius_for_three_points(x[i], y[i], x[j], y[j], x[k], y[k])
        if realcompare(r, radius1) == "GT":
            return True
    return False


def _lic10(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of three data points separated by exactly C_PTS and D_PTS consecutive intervening points, respectively, that form an angle such that angle < (PI - EPSILON) or angle > (PI + EPSILON)."""
    c_pts = params["C_PTS"]
    d_pts = params["D_PTS"]
    epsilon = params["EPSILON"]
    if numpoints < 5:
        return False
    for i in range(numpoints - c_pts - d_pts - 2):
        j = i + c_pts + 1
        k = j + d_pts + 1
        angle = _angle_at_vertex(x[i], y[i], x[j], y[j], x[k], y[k])
        if angle < 0:
            continue
        if realcompare(angle, PI - epsilon) == "LT" or realcompare(
            angle, PI + epsilon
        ) == "GT":
            return True
    return False


def _lic11(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of three data points separated by exactly E_PTS and F_PTS consecutive intervening points, respectively, that are the vertices of a triangle with area greater than AREA1."""
    e_pts = params["E_PTS"]
    f_pts = params["F_PTS"]
    area1 = params["AREA1"]
    if numpoints < 5:
        return False
    for i in range(numpoints - e_pts - f_pts - 2):
        j = i + e_pts + 1
        k = j + f_pts + 1
        area = _triangle_area(x[i], y[i], x[j], y[j], x[k], y[k])
        if realcompare(area, area1) == "GT":
            return True
    return False


def _lic12(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of two data points, (X[i], Y[i]) and (X[j], Y[j]), separated by exactly G_PTS consecutive intervening points, such that X[j] - X[i] < 0."""
    g_pts = params["G_PTS"]
    if numpoints < 3:
        return False
    for i in range(numpoints - g_pts - 1):
        j = i + g_pts + 1
        if realcompare(x[j] - x[i], 0.0) == "LT":
            return True
    return False


def _lic13(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of two data points, separated by exactly K_PTS consecutive intervening points, which are a distance greater than LENGTH1 apart.
    In addition, there exists at least one set of two data points (which can be the same or different), separated by exactly K_PTS consecutive intervening points,
    that are a distance less than LENGTH2 apart."""
    k_pts = params["K_PTS"]
    length1 = params["LENGTH1"]
    length2 = params["LENGTH2"]
    if numpoints < 3:
        return False

    found_greater = False
    found_less = False

    for i in range(numpoints - k_pts - 1):
        j = i + k_pts + 1
        dx = x[j] - x[i]
        dy = y[j] - y[i]
        dist_sq = dx * dx + dy * dy
        length1_sq = length1 * length1
        length2_sq = length2 * length2

        if not found_greater and realcompare(dist_sq, length1_sq) == "GT":
            found_greater = True
        if not found_less and realcompare(dist_sq, length2_sq) == "LT":
            found_less = True

        if found_greater and found_less:
            return True

    return found_greater and found_less


def _lic14(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of three data points, separated by exactly A_PTS and B_PTS consecutive intervening points, respectively, that cannot be contained within or on a circle of radius RADIUS1.
    In addition, there exists at least one set of three data points (which can be the same or different), separated by exactly A_PTS and B_PTS consecutive intervening points, respectively,
    that can be contained in or on a circle of radius RADIUS2."""
    a_pts = params["A_PTS"]
    b_pts = params["B_PTS"]
    radius1 = params["RADIUS1"]
    radius2 = params["RADIUS2"]
    if numpoints < 5:
        return False

    found_greater = False
    found_within = False

    for i in range(numpoints - a_pts - b_pts - 2):
        j = i + a_pts + 1
        k = j + b_pts + 1
        r = _circle_radius_for_three_points(x[i], y[i], x[j], y[j], x[k], y[k])

        if not found_greater and realcompare(r, radius1) == "GT":
            found_greater = True
        if not found_within and realcompare(r, radius2) != "GT":
            found_within = True

        if found_greater and found_within:
            return True

    return found_greater and found_within


def _lic15(x: list, y: list, numpoints: int, params: dict) -> bool:
    """There exists at least one set of three data points, separated by exactly E_PTS and F_PTS consecutive intervening points, respectively, that are the vertices of a triangle with area greater than AREA1.
    In addition, there exist three data points (which can be the same or different), separated by exactly E_PTS and F_PTS consecutive intervening points, respectively,
    that are the vertices of a triangle with area less than AREA2."""
    e_pts = params["E_PTS"]
    f_pts = params["F_PTS"]
    area1 = params["AREA1"]
    area2 = params["AREA2"]
    if numpoints < 5:
        return False

    found_greater = False
    found_less = False

    for i in range(numpoints - e_pts - f_pts - 2):
        j = i + e_pts + 1
        k = j + f_pts + 1
        area = _triangle_area(x[i], y[i], x[j], y[j], x[k], y[k])

        if not found_greater and realcompare(area, area1) == "GT":
            found_greater = True
        if not found_less and realcompare(area, area2) == "LT":
            found_less = True

        if found_greater and found_less:
            return True

    return found_greater and found_less


def _compute_cmv(x: list, y: list, numpoints: int, params: dict) -> list:
    """Compute the Conditions Met Vector (CMV) for all 15 LICs."""
    cmv = [False] * 15
    cmv[0] = _lic1(x, y, numpoints, params)
    cmv[1] = _lic2(x, y, numpoints, params)
    cmv[2] = _lic3(x, y, numpoints, params)
    cmv[3] = _lic4(x, y, numpoints, params)
    cmv[4] = _lic5(x, y, numpoints, params)
    cmv[5] = _lic6(x, y, numpoints, params)
    cmv[6] = _lic7(x, y, numpoints, params)
    cmv[7] = _lic8(x, y, numpoints, params)
    cmv[8] = _lic9(x, y, numpoints, params)
    cmv[9] = _lic10(x, y, numpoints, params)
    cmv[10] = _lic11(x, y, numpoints, params)
    cmv[11] = _lic12(x, y, numpoints, params)
    cmv[12] = _lic13(x, y, numpoints, params)
    cmv[13] = _lic14(x, y, numpoints, params)
    cmv[14] = _lic15(x, y, numpoints, params)
    return cmv


def _compute_pum(cmv: list, lcm: list, pum_diag: list) -> list:
    """Compute the Preliminary Unlocking Matrix (PUM)."""
    pum = [[False] * 15 for _ in range(15)]

    for i in range(15):
        for j in range(15):
            if i == j:
                pum[i][j] = pum_diag[i]
            else:
                connector = lcm[i][j]
                if connector == "NOTUSED":
                    pum[i][j] = True
                elif connector == "ANDD":
                    pum[i][j] = cmv[i] and cmv[j]
                elif connector == "ORR":
                    pum[i][j] = cmv[i] or cmv[j]

    return pum


def _compute_fuv(pum: list) -> list:
    """Compute the Final Unlocking Vector (FUV)."""
    fuv = [False] * 15
    for i in range(15):
        if not pum[i][i]:
            fuv[i] = True
        else:
            all_true = True
            for j in range(15):
                if not pum[i][j]:
                    all_true = False
                    break
            fuv[i] = all_true
    return fuv


def _compute_launch(fuv: list) -> bool:
    """Compute the LAUNCH decision."""
    for val in fuv:
        if not val:
            return False
    return True


def decide(
    numpoints: int, x: list, y: list, parameters: dict, lcm: list, pum_diag: list
) -> tuple:
    """
    Behaviorally equivalent to the Pascal DECIDE procedure.

    Args:
        numpoints: Number of data points (2..100)
        x: List of X coordinates (length numpoints)
        y: List of Y coordinates (length numpoints)
        parameters: Dict with keys matching PARAMETERS record fields
        lcm: 15x15 list of strings ("NOTUSED", "ORR", "ANDD")
        pum_diag: List of 15 bools for PUM diagonal elements

    Returns:
        Tuple (cmv, pum, fuv, launch) where:
        - cmv: 15 bools (Conditions Met Vector)
        - pum: 15x15 bools (Preliminary Unlocking Matrix)
        - fuv: 15 bools (Final Unlocking Vector)
        - launch: bool (final launch decision)
    """
    cmv = _compute_cmv(x, y, numpoints, parameters)
    pum = _compute_pum(cmv, lcm, pum_diag)
    fuv = _compute_fuv(pum)
    launch = _compute_launch(fuv)
    return (cmv, pum, fuv, launch)
